settings.markdownCss:
.entity-header { width:100%; height:100%; display:flex; align-items:center; padding:12px 24px; box-sizing:border-box; background:transparent; }
.main-info { display:flex; align-items:center; gap:20px; width:100%; }
.entity-icon { width:64px; height:64px; border-radius:8px; background:linear-gradient(135deg,#305680 0%,#4a7fb5 100%); display:flex; align-items:center; justify-content:center; flex-shrink:0; }
.entity-icon .material-icons { font-size:34px; color:#fff; }
.entity-details { display:flex; flex-direction:column; gap:6px; min-width:0; flex:1; }
.entity-name { font-family:Roboto,sans-serif; font-size:32px; font-weight:500; color:rgba(0,0,0,0.87); letter-spacing:0.15px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
.entity-meta { display:flex; align-items:center; gap:10px; flex-wrap:wrap; }
.profile-badge { display:inline-flex; align-items:center; padding:4px 14px; border-radius:8px; background:rgba(48,86,128,0.08); color:#305680; font-family:Roboto,sans-serif; font-size:14px; font-weight:500; letter-spacing:0.3px; }
.meta-separator { color:rgba(0,0,0,0.2); font-size:14px; }
.meta-item { display:inline-flex; align-items:center; gap:5px; font-family:Roboto,sans-serif; font-size:14px; color:rgba(0,0,0,0.54); white-space:nowrap; }
.meta-item .material-icons { font-size:17px; }

dataKeys.postFuncBody:
if (!value) return '--';
var d = new Date(value);
var now = new Date();
var diff = now - d;
var s = Math.floor(diff / 1000);
var m = Math.floor(s / 60);
var h = Math.floor(m / 60);
var days = Math.floor(h / 24);
if (s < 60) return 'Just now';
if (m < 60) return m + 'm ago';
if (h < 24) return h + 'h ' + (m % 60) + 'm ago';
if (days < 7) return days + 'd ' + (h % 24) + 'h ago';
return d.toLocaleDateString('en-US', {month:'short', day:'numeric', hour:'2-digit', minute:'2-digit'});

click.customFunction:
const params = widgetContext.stateController.getStateParams();

