    $event, 'emulator-popover', params, true,
    'bottom', true, '500px', '600px'
);

const popovers = widgetContext.popoverComponents;
if (popovers && popovers.length > 0) {
    const popover = popovers[popovers.length - 1];
    popover.tbShowCloseButton = false;
    popover.tbPopoverInnerContentStyle = {
        padding: 0
    };
}

