settings.cellContentFunction:
var ts = value;
if (!ts) return '<span style="color:rgba(0,0,0,0.38)">—</span>';
var now = Date.now();
var diff = now - ts;
var seconds = Math.floor(diff / 1000);
var minutes = Math.floor(seconds / 60);
var hours = Math.floor(minutes / 60);
var days = Math.floor(hours / 24);
var label;
if (seconds < 5) label = 'just now';
else if (seconds < 60) label = seconds + 's ago';
else if (minutes < 60) label = minutes + 'm ago';
else if (hours < 24) label = hours + 'h ago';
else label = days + 'd ago';
var color, bg;
if (minutes < 5) { color = '#2e7d32'; bg = 'rgba(46,125,50,0.08)'; }
else if (minutes < 60) { color = '#e65100'; bg = 'rgba(230,81,0,0.08)'; }
else { color = '#757575'; bg = 'rgba(0,0,0,0.06)'; }
return '<span style="display:inline-flex;align-items:center;gap:4px;padding:4px 10px;' +
    'border-radius:8px;font-size:12px;font-weight:500;background:' + bg + ';color:' + color + ';">' +
    '<span style="width:6px;height:6px;border-radius:50%;background:' + color + ';flex-shrink:0"></span>' +
    label + '</span>';

var v = value || '';
if (!v) return '';
var label = v.replace(/[-_]/g, ' ').replace(/\b\w/g, function(c) { return c.toUpperCase(); });
var palette = [
    { bg: 'rgba(48,86,128,0.10)',  fg: '#305680' },
    { bg: 'rgba(46,125,50,0.10)',  fg: '#2e7d32' },
    { bg: 'rgba(230,81,0,0.10)',   fg: '#e65100' },
    { bg: 'rgba(106,27,154,0.10)', fg: '#6a1b9a' },
    { bg: 'rgba(0,131,143,0.10)',  fg: '#00838f' },
    { bg: 'rgba(191,54,12,0.10)',  fg: '#bf360c' },
    { bg: 'rgba(2,119,189,0.10)',  fg: '#0277bd' },
    { bg: 'rgba(109,76,65,0.10)',  fg: '#6d4c41' }
];
var h = 0;
for (var i = 0; i < v.length; i++) h = ((h << 5) - h + v.charCodeAt(i)) | 0;
var c = palette[Math.abs(h) % palette.length];
return '<span style="display:inline-block;padding:4px 10px;border-radius:8px;' +
    'font-size:12px;font-weight:500;' +
    'background:' + c.bg + ';color:' + c.fg + ';">' +
    label + '</span>';
